+@page "/calendar"
+@using System.Globalization
+@rendermode InteractiveServer
+@inject ICalendarService CalendarService
+
+<PageTitle>Team Calendar</PageTitle>
+
+<div class="calendar-container">
+    <div class="calendar-main">
+        <!-- Month Navigation Bar -->
+        <div class="month-nav">
+            <button class="btn btn-outline-secondary" @onclick="PreviousMonth">Previous</button>
+            <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
+            <h3 class="month-label">@currentDate.ToString("MMMM yyyy")</h3>
+            <button class="btn btn-outline-secondary" @onclick="NextMonth">Next</button>
+        </div>
+
+        <!-- Team Member Filter -->
+        <div class="team-filter">
+            <button class="btn btn-sm btn-link" @onclick="ToggleSelectAll">
+                @(allSelected ? "Deselect All" : "Select All")
+            </button>
+            @foreach (var member in teamMembers)
+            {
+                <label class="filter-checkbox">
+                    <input type="checkbox" checked="@selectedMembers.Contains(member)"
+                           @onchange="e => ToggleMember(member, (bool)e.Value!)" />
+                    @member
+                </label>
+            }
+        </div>
+
+        <!-- Calendar Grid -->
+        <div class="calendar-grid">
+            @foreach (var day in new[] { "Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun" })
+            {
+                <div class="calendar-header">@day</div>
+            }
+            @foreach (var day in calendarDays)
+            {
+                var dayDate = day.Date;
+                var isToday = dayDate == DateTime.Today;
+                var isCurrentMonth = dayDate.Month == currentDate.Month && dayDate.Year == currentDate.Year;
+                var isSelected = dayDate == selectedDate;
+                var dayEvents = GetFilteredEventsForDay(dayDate);
+
+                <div class="calendar-cell @(isToday ? "today" : "") @(!isCurrentMonth ? "dimmed" : "") @(isSelected ? "selected" : "")"
+                     @onclick="() => SelectDay(dayDate)">
+                    <span class="day-number">@dayDate.Day</span>
+                    <div class="event-dots">
+                        @if (dayEvents.Count > 0)
+                        {
+                            @for (int i = 0; i < Math.Min(dayEvents.Count, 3); i++)
+                            {
+                                <span class="dot"></span>
+                            }
+                            @if (dayEvents.Count > 3)
+                            {
+                                <span class="more-label">+@(dayEvents.Count - 3) more</span>
+                            }
+                        }
+                    </div>
+                </div>
+            }
+        </div>
+    </div>
+
+    <!-- Day Detail Side Panel -->
+    @if (selectedDate.HasValue)
+    {
+        <div class="day-panel">
+            @if (!showNewEventForm)
+            {
+                <h4>@selectedDate.Value.ToString("dddd, MMMM d, yyyy")</h4>
+
+                @{ var dayEventsList = GetFilteredEventsForDay(selectedDate.Value); }
+
+                @if (dayEventsList.Count == 0)
+                {
+                    <p class="no-events">No events scheduled</p>
+                }
+                else
+                {
+                    <div class="event-list">
+                        @foreach (var evt in dayEventsList)
+                        {
+                            <div class="event-card">
+                                <div class="event-title">@evt.Title</div>
+                                <div class="event-time">@FormatTime(evt.StartTime) &ndash; @FormatTime(evt.EndTime)</div>
+                                <div class="event-attendees">@string.Join(", ", evt.Attendees)</div>
+                                <button class="btn btn-sm btn-danger" @onclick="() => DeleteEvent(evt.Id)">Delete</button>
+                            </div>
+                        }
+                    </div>
+                }
+
+                <button class="btn btn-primary mt-3" @onclick="ShowNewEventForm">New Event</button>
+            }
+            else
+            {
+                <!-- New Event Form -->
+                <h4>New Event</h4>
+                <div class="new-event-form">
+                    <div class="form-group">
+                        <label>Title</label>
+                        <input type="text" class="form-control" @bind="newEventTitle" />
+                    </div>
+                    <div class="form-group">
+                        <label>Date</label>
+                        <input type="date" class="form-control" @bind="newEventDate" />
+                    </div>
+                    <div class="form-group">
+                        <label>Start Time</label>
+                        <input type="time" class="form-control" @bind="newEventStartTime" />
+                    </div>
+                    <div class="form-group">
+                        <label>End Time</label>
+                        <input type="time" class="form-control" @bind="newEventEndTime" />
+                    </div>
+                    <div class="form-group">
+                        <label>Attendees</label>
+                        @foreach (var member in teamMembers)
+                        {
+                            <label class="filter-checkbox">
+                                <input type="checkbox" checked="@newEventAttendees.Contains(member)"
+                                       @onchange="e => ToggleNewEventAttendee(member, (bool)e.Value!)" />
+                                @member
+                            </label>
+                        }
+                    </div>
+                    <div class="form-actions">
+                        <button class="btn btn-success" @onclick="SaveNewEvent">Save</button>
+                        <button class="btn btn-secondary" @onclick="CancelNewEvent">Cancel</button>
+                    </div>
+                </div>
+            }
+        </div>
+    }
+</div>
+
+@code {
+    private DateTime currentDate = new DateTime(DateTime.Today.Year, DateTime.Today.Month, 1);
+    private DateTime? selectedDate;
+    private List<string> teamMembers = new();
+    private HashSet<string> selectedMembers = new();
+    private List<CalendarEvent> events = new();
+    private List<DateTime> calendarDays = new();
+
+    // New event form state
+    private bool showNewEventForm;
+    private string newEventTitle = "";
+    private DateTime newEventDate = DateTime.Today;
+    private TimeSpan newEventStartTime = new(9, 0, 0);
+    private TimeSpan newEventEndTime = new(10, 0, 0);
+    private HashSet<string> newEventAttendees = new();
+
+    private bool allSelected => teamMembers.Count > 0 && selectedMembers.Count == teamMembers.Count;
+
+    protected override async Task OnInitializedAsync()
+    {
+        teamMembers = await CalendarService.GetTeamMembersAsync();
+        selectedMembers = new HashSet<string>(teamMembers);
+        await LoadEvents();
+        BuildCalendarDays();
+    }
+
+    private async Task LoadEvents()
+    {
+        events = await CalendarService.GetEventsAsync(currentDate.Year, currentDate.Month);
+    }
+
+    private void BuildCalendarDays()
+    {
+        calendarDays = new List<DateTime>();
+        var firstOfMonth = new DateTime(currentDate.Year, currentDate.Month, 1);
+        var startDay = firstOfMonth.DayOfWeek == DayOfWeek.Sunday ? 6 : (int)firstOfMonth.DayOfWeek - 1;
+        var start = firstOfMonth.AddDays(-startDay);
+
+        for (int i = 0; i < 42; i++)
+        {
+            calendarDays.Add(start.AddDays(i));
+        }
+    }
+
+    private List<CalendarEvent> GetFilteredEventsForDay(DateTime date)
+    {
+        return events
+            .Where(e => e.Date.Date == date.Date && e.Attendees.Any(a => selectedMembers.Contains(a)))
+            .ToList();
+    }
+
+    private async Task PreviousMonth()
+    {
+        currentDate = currentDate.AddMonths(-1);
+        await LoadEvents();
+        BuildCalendarDays();
+    }
+
+    private async Task NextMonth()
+    {
+        currentDate = currentDate.AddMonths(1);
+        await LoadEvents();
+        BuildCalendarDays();
+    }
+
+    private async Task GoToToday()
+    {
+        currentDate = new DateTime(DateTime.Today.Year, DateTime.Today.Month, 1);
+        selectedDate = DateTime.Today;
+        showNewEventForm = false;
+        await LoadEvents();
+        BuildCalendarDays();
+    }
+
+    private void SelectDay(DateTime date)
+    {
+        selectedDate = date;
+        showNewEventForm = false;
+    }
+
+    private void ToggleMember(string member, bool isChecked)
+    {
+        if (isChecked)
+            selectedMembers.Add(member);
+        else
+            selectedMembers.Remove(member);
+    }
+
+    private void ToggleSelectAll()
+    {
+        if (allSelected)
+            selectedMembers.Clear();
+        else
+            selectedMembers = new HashSet<string>(teamMembers);
+    }
+
+    private async Task DeleteEvent(int eventId)
+    {
+        await CalendarService.DeleteEventAsync(eventId);
+        await LoadEvents();
+    }
+
+    private void ShowNewEventForm()
+    {
+        showNewEventForm = true;
+        newEventTitle = "";
+        newEventDate = selectedDate ?? DateTime.Today;
+        newEventStartTime = new TimeSpan(9, 0, 0);
+        newEventEndTime = new TimeSpan(10, 0, 0);
+        newEventAttendees = new HashSet<string>();
+    }
+
+    private void CancelNewEvent()
+    {
+        showNewEventForm = false;
+    }
+
+    private async Task SaveNewEvent()
+    {
+        if (string.IsNullOrWhiteSpace(newEventTitle))
+            return;
+
+        await CalendarService.CreateEventAsync(
+            newEventTitle,
+            newEventDate,
+            newEventStartTime,
+            newEventEndTime,
+            newEventAttendees.ToList());
+
+        showNewEventForm = false;
+        // Refresh events for current month view
+        currentDate = new DateTime(newEventDate.Year, newEventDate.Month, 1);
+        await LoadEvents();
+        BuildCalendarDays();
+    }
+
+    private void ToggleNewEventAttendee(string member, bool isChecked)
+    {
+        if (isChecked)
+            newEventAttendees.Add(member);
+        else
+            newEventAttendees.Remove(member);
+    }
