.calendar-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.calendar-main {
    flex: 1;
}

/* Month Navigation */
.month-nav {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1rem;
}

.month-label {
    flex: 1;
    text-align: center;
    margin: 0;
}

/* Team Filter */
.team-filter {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    cursor: pointer;
    margin: 0;
}

/* Calendar Grid */
.calendar-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 1px;
    background: #dee2e6;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    overflow: hidden;
}

.calendar-header {
    background: #e9ecef;
    padding: 0.5rem;
    text-align: center;
    font-weight: 600;
    font-size: 0.85rem;
}

.calendar-cell {
    background: #fff;
    min-height: 5rem;
    padding: 0.4rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.calendar-cell:hover {
    background: #f0f7ff;
}

.calendar-cell.today {
    background: #e8f4fd;
    border: 2px solid #0d6efd;
}

.calendar-cell.dimmed {
    background: #f8f9fa;
    color: #adb5bd;
}

.calendar-cell.selected {
    background: #cfe2ff;
}

.day-number {
    font-weight: 600;
    font-size: 0.9rem;
}

.event-dots {
    display: flex;
    flex-wrap: wrap;
    gap: 3px;
    margin-top: 0.25rem;
    align-items: center;
}

.dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #0d6efd;
}

.more-label {
    font-size: 0.7rem;
    color: #6c757d;
}

