    background: #fff;
    min-height: 5rem;
    padding: 0.4rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.calendar-cell:hover {
    background: #f0f7ff;
}

.calendar-cell.today {
    background: #e8f4fd;
    border: 2px solid #0d6efd;
}

.calendar-cell.dimmed {
    background: #f8f9fa;
    color: #adb5bd;
}

.calendar-cell.selected {
    background: #cfe2ff;
}

.day-number {
    font-weight: 600;
    font-size: 0.9rem;
}

.event-dots {
    display: flex;
    flex-wrap: wrap;
    gap: 3px;
    margin-top: 0.25rem;
    align-items: center;
}

.dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #0d6efd;
}

.more-label {
    font-size: 0.7rem;
    color: #6c757d;
}

