    align-self: flex-start;
    max-height: 80vh;
    overflow-y: auto;
}

.no-events {
    color: #6c757d;
    font-style: italic;
}

.event-list {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.event-card {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.event-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.event-time {
    font-size: 0.85rem;
    color: #495057;
}

.event-attendees {
    font-size: 0.8rem;
    color: #6c757d;
    margin-bottom: 0.5rem;
}

/* New Event Form */
.new-event-form .form-group {
    margin-bottom: 0.75rem;
}

.new-event-form .form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.25rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 1rem;
}

.mt-3 {
    margin-top: 1rem;
}

